class AppUserProfile { final String id, fullName, mobileNumber; final String? email, avatarUrl; AppUserProfile({required this.id,required this.fullName,required this.mobileNumber,this.email,this.avatarUrl}); factory AppUserProfile.fromMap(Map<String,dynamic> m)=>AppUserProfile(id:(m['id']??'').toString(),fullName:(m['full_name']??'').toString(),mobileNumber:(m['mobile_number']??'').toString(),email:m['email']?.toString(),avatarUrl:m['avatar_url']?.toString()); Map<String,dynamic> toUpsert()=>{'id':id,'full_name':fullName,'mobile_number':mobileNumber,'email':email,'updated_at':DateTime.now().toUtc().toIso8601String()}; }
